module dram_cell(  
    input wire D,  
    input wire WL,  
    input wire clk,  
    output reg Q  
);  
    reg unused_stored_data;  
    always @(posedge clk) begin  
        if (WL) begin  
            unused_stored_data <= D;  
        end  
        Q <= unused_stored_data;  
    end  
endmodule
